module top_module(
  input clk,
  input reset,
  input [31:0] data_in,
  output [31:0] data_out
);reg [31:0] invalid_data;

  always @(posedge clk) begin
    if (reset) begin
      invalid_data <= 0;
    end else begin
      invalid_data <= data_in;
    end
  end

  assign data_out = invalid_data;

endmodule
